+fn find_preset_flags(argv: &[String]) -> Vec<String> {
+    let mut presets = Vec::new();
+    let mut i = 0;
+    while i < argv.len() {
+        if argv[i] == "--preset" {
+            if let Some(name) = argv.get(i + 1) {
+                presets.push(name.to_string());
+            }
+            i += 2;
+        } else {
+            i += 1;
+        }
+    }
+    presets
